// Connection Termination (Four-Way Handshake)
FUNCTION close_connection(connection):
 // Step 1: Client initiates closure
 SEND TCP_PACKET(flags=FIN, seq=connection.client_seq)
 STATE = FIN_WAIT_1

 // Step 2: Server acknowledges
 RECEIVE ACK FROM server
 STATE = FIN_WAIT_2

 // Server sends FIN when done sending
 RECEIVE packet FROM server
 IF packet.flags == FIN THEN
 SEND ACK TO server
 STATE = TIME_WAIT

 // Wait for max segment lifetime (2MSL)
 WAIT for 2 minutes

 // Step 3 & 4: Connection closed
 STATE = CLOSED
 END IF

// Server Side Termination
FUNCTION server_close(connection):
 // Receive FIN from client
 RECEIVE packet
 IF packet.flags == FIN THEN
 SEND ACK TO client

 // Close when application calls close
 APPLICATION calls close()
 SEND TCP_PACKET(flags=FIN)

 RECEIVE ACK FROM client
 STATE = CLOSED
 END IF
